insert into alternatives (id, slug, name, brand, basis_text, basis_confidence, basis_sources, affiliate_url, affiliate_type, category, image_url) values
  ('5dd34370-e2f9-4094-8df5-7f2f478d3056', 'bobs-red-mill-baking-soda', 'Baking Soda', 'Bob''s Red Mill', 'Founder Bob Moore was a committed Christian; multiple sources document his faith as the explicit motivation for company policy, including giving the company to employees via an ESOP.', 1, ARRAY['https://en.wikipedia.org/wiki/Bob_Moore_(executive)', 'https://www.klove.com/news/faith/founder-of-bob-s-red-mill-committed-christian-generous-boss-9757'], NULL, 'amazon', 'Household & Cleaning', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Bob''s%20Red%20Mill%20Baking%20Soda'),
  ('75ec85ab-8492-499e-b5d4-3587be30dfac', 'boll-weevil-soap-co', 'Soap / Body Wash', 'Boll Weevil Soap Company', 'Explicitly self-identifies as a Christian-owned family soap business, citing Colossians 3:17 on its own About page.', 2, ARRAY['https://bollweevilsoapcompany.com/pages/about-us'], NULL, 'amazon', 'Soap & Body', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Boll%20Weevil%20Soap%20Co.'),
  ('5c12c470-b087-4f97-a038-54edc7675174', 'faithfully-natural-soap-co', 'Soap / Body Wash', 'Faithfully Natural Soap Co.', 'Explicitly self-identifies as a Christian-owned family soap business on its own site.', 2, ARRAY['https://faithfullynaturalsoapco.com/pages/about-us'], 'https://faithfullynaturalsoapco.com', 'direct', 'Soap & Body', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Faithfully%20Natural%20Soap%20Co.'),
  ('23a5513f-3c2b-4184-9038-0468ee4e63c8', 'pure-hearts-clean-hands-soap-co', 'Soap / Body Wash', 'Pure Hearts & Clean Hands Soap Co.', 'Explicitly self-identifies as a Christian-owned family soap business on its own site.', 2, ARRAY['https://phchnaturalsoap.net/about-us/'], 'https://phchnaturalsoap.net', 'direct', 'Soap & Body', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Pure%20Hearts%20%26%20Clean%20Hands'),
  ('0017d285-d2b3-4348-bdb5-3c1d13c17b68', 'branch-basics-all-purpose-concentrate', 'All-Purpose Cleaner Concentrate', 'Branch Basics', 'Co-founder Allison Evans states in a published interview, "we share a common faith, which we all fall back on," and founders discuss their Christian faith on the Thriving Beyond Belief podcast.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/', 'https://thrivingbeyondbelief.com/046-branch-basics-with-allison-evans-marilee-nelson/'], NULL, 'amazon', 'Household & Cleaning', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Branch%20Basics%20All-Purpose'),
  ('bf9f3fd7-0204-44e0-aefe-e7eec320cbc4', 'branch-basics-oxygen-boost', 'Oxygen Boost Stain Remover', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Branch%20Basics%20Oxygen%20Boost'),
  ('0f3ac2d7-f834-4fdb-8b81-865b106c732d', 'branch-basics-laundry-concentrate', 'Laundry Concentrate', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Branch%20Basics%20Laundry'),
  ('199c293f-b229-43bf-beeb-fcdccf47a02c', 'provherbs-herbal-supplements', 'Herbal Supplements / Tinctures', 'Provherbs', 'Company''s own "Our Story" page: "we look first to Christ. He is the center in all that we do."', 1, ARRAY['https://provherbs.com/pages/our-story'], 'https://provherbs.com', 'direct', 'Supplements', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Provherbs%20Supplements'),
  ('00bb4165-4a1e-4736-9a1c-842b4d0b2852', 'eleven86-artesian-water', 'Real Artesian Water', 'Eleven86', 'Company''s own tagline: "Faith in every drop. Purpose in every bottle."', 1, ARRAY['https://www.eleven86water.com/our-story'], 'https://www.eleven86water.com', 'unconfirmed', 'Food & Beverage', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Eleven86%20Water'),
  ('08af0a24-f602-4d3d-9ea3-abefeeb82d99', 'bold3-coffee', 'Coffee (whole bean & ground)', 'BOLD3 Coffee', '501(c)(3) Christian nonprofit ministry. Own listing states: "BOLD3 Coffee is a Christian Non-profit Ministry on a mission to empower others to be BOLD and spread the Hope of Christ worldwide." Every bag purchased delivers God''s Word into the hands of 3 children.', 1, ARRAY['https://www.amazon.com/BOLD3-coffee-Colombian-Ethiopian-Nicaragua/dp/B07F2J6MHV', 'https://www.bold3.org/'], NULL, 'amazon', 'Food & Beverage', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=BOLD3%20Coffee'),
  ('9b3968b9-27fe-45fb-bcd6-4a46ce7e4ae8', 'palm-beach-herbal-tea', 'Herbal Tea', 'Palm Beach Herbal Tea Company', 'Explicitly self-identifies as a "Christian based, family-owned herbal tea company" on its own site.', 1, ARRAY['https://palmbeachherbalteas.com/pages/our-story'], NULL, 'amazon', 'Food & Beverage', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Palm%20Beach%20Herbal%20Tea'),
  ('ed231576-664f-4417-b37f-1c32b07d5024', 'everylife-diapers-wipes', 'Diapers + Wipes', 'EveryLife', 'Co-founders explicitly state "every child is a miracle from God"; company''s own mission page: "We unapologetically choose to celebrate life. Every child is a gift from above."', 1, ARRAY['https://everylife.com/pages/our-mission', 'https://www.oursundayvisitor.com/meet-the-founders-of-everylife-a-new-pro-life-diaper-company/'], 'https://everylife.com', 'unconfirmed', 'Baby Products', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=EveryLife%20Diapers'),
  ('a11d51bf-c090-4116-ab02-cffcfa6fac12', 'earth-eden-diapers', 'Diapers', 'Earth & Eden', 'Not a confirmed Christian-founded brand, but the closest Amazon-available, non-toxic, plant-based diaper option — offered as a secondary pick alongside EveryLife.', 2, ARRAY['https://www.earthandedenbrand.com/'], NULL, 'amazon', 'Baby Products', 'https://placehold.co/400x300/F2E8D8/241A12?font=roboto&text=Earth%20%26%20Eden%20Diapers');
insert into associations (product_id, claim_text, source_urls, confidence_tier, theme_tag, date_checked) values
  ('fdc94a65-729f-48a4-8023-6c54523b697a', 'Logo depicts Vulcan, the Roman god of fire and metalworking — confirmed by the company''s own brand history.', ARRAY['https://www.armandhammer.com/en/about-us', 'https://en.wikipedia.org/wiki/Arm_%26_Hammer', 'https://en.wikipedia.org/wiki/Vulcan_(mythology)'], 1, 'roman-mythology', '2026-07-01'),
  ('1706b1c2-e5e0-44b2-9c36-479a8a9035d9', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-01'),
  ('4a8345e7-6962-4200-97a2-831f9211f5e2', 'Entire collection is structured as a tarot-style "deck" of named fortune cards (The Illusionist, The Sovereign, The Sage, and more). Each bottle includes a QR code for a "shower reading" and a daily "manifestation." Method''s own product copy reads: "Are you ready to hear your fortune? Shoot for the stars today with a body wash that offers a glimpse into your future." This is scoped to the limited-edition Shower Readings line only — Method''s everyday cleaners carry no such theme and are not flagged.', ARRAY['https://methodproducts.com/pages/shower-readings', 'https://www.ulta.com/p/limited-edition-shower-readings-body-wash-pimprod2052565'], 1, 'fortune-telling', '2026-07-01'),
  ('d61e7f9a-fff8-42ef-bb97-44266031e165', 'The mascot was deliberately designed as a genie at P&G''s own direction. A 2014 NYT obituary for original illustrator Richard Black quotes P&G''s communications manager: the company wanted "magic from a bottle" represented by a genie, and the artist was directed to draw one. Genies/jinn originate in Arabic and Islamic folklore.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('d8601757-ee77-404b-9ede-8de102c7d7c5', 'Named after Ajax (Telamonian Ajax), Greek mythological hero of the Trojan War, second in strength only to Achilles. Current marketing leans into it directly: "Stronger than dirt," with copy describing customers as "everyday heroes."', ARRAY['https://en.wikipedia.org/wiki/Ajax_the_Great', 'https://greekcitytimes.com/2022/06/03/hidden-ancient-greek-meaning-behind-ajax-brand-name/'], 1, 'greek-mythology', '2026-07-01'),
  ('e4ad3a10-c352-43fc-a5fa-24d665ef919c', 'Directly named after the Greek/Roman hero Hercules. The company''s own current product pages use the line "Behold the power of Hercules, products built to last and trusted by plumbers."', ARRAY['https://www.oatey.com/products/hercules-glug-kitchen-liquid-drain-opener--782826565'], 1, 'greek-mythology', '2026-07-01'),
  ('ac8bfcd7-ed7a-46d9-bca0-2201012ec2f8', 'Entire product line is built around named crystals with stated metaphysical properties (rose quartz for "joy," amethyst for "dream state," peridot for "balance and control your thoughts"). Marketing copy: "Call in your crystal super power. Crystal-infused and plant-powered."', ARRAY['https://www.pacificabeauty.com/collections/aromapower', 'https://www.ulta.com/brand/pacifica?category=fragrance'], 1, 'crystal-metaphysics', '2026-07-01'),
  ('6eff0f06-f65a-445e-9355-2727cd6c8b0a', 'Founded by Yogi Bhajan, who introduced Kundalini Yoga to the US; the tea recipe and brand are explicitly built on Ayurvedic philosophy. The company''s own "our story" copy still cites Ayurveda as the foundation.', ARRAY['https://en.wikipedia.org/wiki/Yogi_Tea'], 1, 'ayurvedic', '2026-07-01'),
  ('2c2a3457-d58b-4633-931e-b9ef930ef836', 'Documented marketing campaigns built on witchcraft/occult themes: the company hired a self-described witch doctor in 2019 to publicly "hex" inventory as a Halloween stunt, and sold "sell your soul" branded merchandise with a mock contract for the buyer''s "Eternal Soul." These campaigns themselves are documented fact; describing the brand as "satanic" is contested commentary, not a company statement.', ARRAY['https://www.adweek.com/creativity/drink-at-your-own-risk-liquid-death-hires-witch-doctor-to-hex-its-water/', 'https://www.westernjournal.com/liquid-death-water-brand-offered-buy-customers-souls-even-offers-contract-put-satanic-deal-writing/'], 2, 'occult-marketing', '2026-07-01'),
  ('839bddcc-3b03-42de-aaca-80a0181b99c2', 'Named directly after Gaia, the Greek primordial Earth goddess and mother of all life in Greek mythology. Confirmed by the founder''s own company history (founded 1986/1987 by herbalist Ric Scalzo).', ARRAY['https://www.peoplespharmacy.com/articles/introducing-gaia-herbs'], 1, 'greek-mythology', '2026-07-01'),
  ('12cd321e-54fe-4241-b9eb-8d1ed0110afa', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner — P&G''s own communications manager confirmed to the NYT that the mascot was deliberately designed as a genie.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('d7a41f93-adea-438f-8da3-e9350ab20f31', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('619fa5d6-84cb-4ad3-bdab-ab68d7e18d75', 'Brand name is explicitly drawn from an ancient Iroquois Great Law of Peace philosophy. The company''s own website states: "Our name is inspired by an ancient Iroquois philosophy which instructs that in our every deliberation, we must consider the impact of our decisions on the next seven generations."', ARRAY['https://www.seventhgeneration.com/blog/origin-our-name-seventh-generation', 'https://www.fastcompany.com/665006/great-law-iroquois-confederacy'], 1, 'indigenous-philosophy', '2026-07-01'),
  ('3bec69b3-cff8-495f-a9e7-59e73dce03f4', 'Logo is a twin-tailed siren from Greek mythology, confirmed on the company''s own "Story of the Siren" page: "it depicted a siren, a seductive twin-tailed mermaid from Greek mythology who enticed passing sailors to their doom with her enchanting song."', ARRAY['https://about.starbucks.com/history/the-story-of-the-siren/'], 1, 'greek-mythology', '2026-07-01'),
  ('0175f5d4-c6ca-47f4-a8b4-5f61b8444f5e', 'Name and branding deliberately center on death-themed imagery. The company''s own website states: "To some, a death wish may sound irresponsible, morbid, a step too far — but we believe it is the boldest sign of living life to the fullest." This is secular dark/death-themed branding, not tied to a specific mythology or occult practice.', ARRAY['https://www.forbes.com/sites/forbestreptalks/2016/02/09/meet-the-entrepreneur-behind-the-super-bowl-coffee-ad/', 'https://en.wikipedia.org/wiki/Death_Wish_Coffee'], 1, 'secular-death-themed', '2026-07-01'),
  ('f32d433f-cadb-4a75-9073-543afc055130', 'Founder Jessica Alba publicly shared Instagram content in August 2024 involving occult/spiritual practices (numerology, astrology, crystals, and sage burning). Alba had stepped down as Chief Creative Officer in April 2024, before the posts, so she was no longer a company officer at the time, and the brand''s own products carry no occult imagery or branding. This is the founder''s personal social media activity, not a company branding decision.', ARRAY['https://www.instagram.com/p/C_bp7Qpu-hr/'], 2, 'founder-personal-conduct', '2026-07-01');
